// Determine if this is an invoice order that requires QR-Bill generation
const order = $input.item.json.order || $input.item.json;
const paymentGateways = order.payment_gateway_names || [];
const paymentTermsType = order.payment_terms?.payment_terms_type;

// Check for invoice payment:
// 1. Shop order with "Invoice" or "Rechnung" gateway
// 2. POS order with payment_terms_type === "receipt"
const isInvoiceOrder = 
  paymentGateways.some(g => g.toLowerCase().includes('invoice') || g.toLowerCase().includes('rechnung')) ||
  paymentTermsType === 'receipt';

return {
  json: {
    ...($input.item.json),
    _isInvoiceOrder: isInvoiceOrder,
    _routeTo: isInvoiceOrder ? 'qr_invoice' : 'archive_only'
  },
  binary: $input.item.binary
};

// Calculate 27-digit QRR Reference with Modulo 10 recursive check digit
const data = $input.item.json;
const order = data.order || data;

// Extract order number (without # prefix)
const orderNumber = String(order.order_number || order.name || '').replace(/^#/, '');

// Extract date from created_at (YYYYMMDD)
const createdAt = new Date(order.created_at);
const dateStr = createdAt.toISOString().slice(0, 10).replace(/-/g, '');

// Build base reference: YYYYMMDD + OrderNumber
const baseRef = dateStr + orderNumber;

// Pad to 26 digits with leading zeros
const paddedRef = baseRef.padStart(26, '0');

// Modulo 10 recursive algorithm for check digit
function calculateMod10Recursive(ref) {
  const table = [0, 9, 4, 6, 8, 2, 7, 1, 3, 5];
  let carry = 0;

  for (const char of ref) {
    carry = table[(carry + parseInt(char, 10)) % 10];
  }

  return (10 - carry) % 10;
}

const checkDigit = calculateMod10Recursive(paddedRef);
const qrrReference = paddedRef + checkDigit;

// Validate: must be 27 digits
if (!/^\d{27}$/.test(qrrReference)) {
  throw new Error(`Invalid QRR reference: ${qrrReference}`);
}

return {
  json: {
    ...data,
    _qrrReference: qrrReference,
    _qrrReferenceFormatted: qrrReference.replace(/(\d{5})/g, '$1 ').trim()
  },
  binary: $input.item.binary
};

// Map Shopify billing_address to QR-Invoice API format (ultimateDebtor)
const data = $input.item.json;
const order = data.order || data;
const billing = order.billing_address;

if (!billing) {
  throw new Error('No billing_address found in order data');
}

// Name: Company if available, otherwise First + Last name
const name = billing.company 
  ? billing.company 
  : `${billing.first_name || ''} ${billing.last_name || ''}`.trim();

// Extract street name and house number from address1
// Pattern: "Streetname 123" or "Streetname 123a"
const addressMatch = billing.address1?.match(/^(.+?)\s+(\d+\w*)$/);
let streetName, houseNumber;

if (addressMatch) {
  streetName = addressMatch[1];
  houseNumber = addressMatch[2];
} else {
  // Fallback: entire address as street name
  streetName = billing.address1 || '';
  houseNumber = '';
}

// Validation: check required fields
const errors = [];
if (!name) errors.push('Name is required');
if (!billing.zip) errors.push('ZIP/postal code is required');
if (!billing.city) errors.push('City is required');
if (!billing.country_code || billing.country_code.length !== 2) errors.push('Country code invalid (must be 2 chars)');

if (errors.length > 0) {
  throw new Error(`Address validation failed: ${errors.join(', ')}`);
}

// Build ultimateDebtor object with max field lengths
const ultimateDebtor = {
  addressType: 'STRUCTURED',
  name: name.substring(0, 70),
  streetName: (streetName || '').substring(0, 70),
  houseNumber: (houseNumber || '').substring(0, 16),
  postalCode: billing.zip.substring(0, 16),
  city: billing.city.substring(0, 35),
  country: billing.country_code.toUpperCase()
};

return {
  json: {
    ...data,
    _ultimateDebtor: ultimateDebtor
  },
  binary: $input.item.binary
};

// Build QR Invoice Payload for qr-invoice.cloud API
const data = $input.item.json;
const order = data.order || data;

// Get data from previous nodes
const qrrReference = data._qrrReference;
const ultimateDebtor = data._ultimateDebtor;

if (!qrrReference) {
  throw new Error('Missing _qrrReference from Calculate QRR Reference node');
}
if (!ultimateDebtor) {
  throw new Error('Missing _ultimateDebtor from Map Debtor Address node');
}

// Amount as number
const amount = parseFloat(order.total_price);
if (isNaN(amount) || amount <= 0) {
  throw new Error(`Invalid amount: ${order.total_price}`);
}

// Currency (only CHF or EUR allowed)
const currency = order.currency === 'EUR' ? 'EUR' : 'CHF';

// Order number (without #)
const orderNumber = String(order.order_number || order.name || '').replace(/^#/, '');

// Invoice date for billInformation (YYMMDD)
const invoiceDate = new Date(order.created_at);
const invoiceDateFormatted = invoiceDate.toISOString().slice(2, 10).replace(/-/g, '');

// billInformation (Swico S1 Format)
// Tag 10: Invoice number (Order Number)
// Tag 11: Invoice date (YYMMDD)
// Tag 30: UID (without CHE- and separators)
const uid = '507842837'; // Studio3000 GmbH UID
const billInformation = `//S1/10/${orderNumber}/11/${invoiceDateFormatted}/30/${uid}`;

// Creditor (static for Studio3000 GmbH)
const creditor = {
  addressType: 'STRUCTURED',
  name: 'Studio3000 GmbH',
  streetName: 'Bachstrasse',
  houseNumber: '33',
  postalCode: '5034',
  city: 'Suhr',
  country: 'CH'
};

// QR-IBAN
const iban = 'CH423000523078572701L';

// Build complete QrInvoice object
const qrInvoice = {
  creditorInformation: {
    iban: iban,
    creditor: creditor
  },
  paymentAmountInformation: {
    amount: amount,
    currency: currency
  },
  paymentReference: {
    referenceType: 'QRR',
    reference: qrrReference,
    additionalInformation: {
      unstructuredMessage: `Rechnung #${orderNumber} Tuftinglove.com`.substring(0, 140),
      billInformation: billInformation.substring(0, 140)
    }
  },
  ultimateDebtor: ultimateDebtor
};

return {
  json: {
    ...data,
    _qrInvoice: qrInvoice,
    _orderNumber: orderNumber,
    _amount: amount,
    _currency: currency
  },
  binary: $input.item.binary
};

// Collect both PDFs for merge
const data = $input.item.json;

// Get original invoice from Download Original Invoice node
const originalInvoiceNode = $('Download Original Invoice').first();
if (!originalInvoiceNode?.binary?.originalInvoice) {
  throw new Error('Original invoice binary not found from Download Original Invoice node');
}

// Get QR payment part from current input (Generate QR Payment Part)
const qrPaymentPart = $input.item.binary?.qrPaymentPart;
if (!qrPaymentPart) {
  throw new Error('QR Payment Part binary not found from Generate QR Payment Part node');
}

return {
  json: {
    ...data
  },
  binary: {
    originalInvoice: originalInvoiceNode.binary.originalInvoice,
    qrPaymentPart: qrPaymentPart
  }
};

// Calculate Due Date based on order type
// - Invoice orders: Order date + 30 days
// - Non-invoice orders: Order date (same day)

const data = $input.item.json;
const order = data.order || data._order || data;

// Check if this is an invoice order
const isInvoiceOrder = data._isInvoiceOrder === true;

// Invoice date from order
const invoiceDate = new Date(order.created_at);

// Due date calculation
const dueDate = new Date(invoiceDate);
if (isInvoiceOrder) {
  // Invoice orders: due in 30 days
  dueDate.setDate(dueDate.getDate() + 30);
} else {
  // Non-invoice orders: due date = order date (already paid)
  // Keep dueDate as invoiceDate (no change)
}

// ISO format for Shopify (YYYY-MM-DD)
const dueDateISO = dueDate.toISOString().split('T')[0];
const invoiceDateISO = invoiceDate.toISOString().split('T')[0];

// Order ID for Shopify GraphQL (needs gid format)
const orderId = order.id || order.admin_graphql_api_id;
const orderGid = orderId.toString().startsWith('gid://') 
  ? orderId 
  : `gid://shopify/Order/${orderId}`;

return {
  json: {
    ...data,
    _orderId: orderId,
    _orderGid: orderGid,
    _orderName: order.name,
    _invoiceDate: invoiceDateISO,
    _dueDate: dueDateISO,
    _isInvoiceOrder: isInvoiceOrder
  },
  binary: $input.item.binary
};

