={
  "query": "mutation orderUpdate($input: OrderInput!) { orderUpdate(input: $input) { order { id metafields(first: 5) { edges { node { namespace key value } } } } userErrors { field message } } }",
  "variables": {
    "input": {
      "id": "{{ $json._orderGid }}",
      "metafields": [
        {
          "namespace": "custom",
          "key": "qr_invoice_due_date",
          "value": "{{ $json._dueDate }}",
          "type": "date"
        },
        {
          "namespace": "custom",
          "key": "qr_invoice",
          "value": "{{ $json._gdrive.shareUrl }}",
          "type": "url"
        },
        {
          "namespace": "custom",
          "key": "qr_invoice_gdrive_link",
          "value": "{{ $json._gdrive.shareUrl }}",
          "type": "url"
        }
      ]
    }
  }
}

