// Generate random filename for security (no order number in public URL)
const data = $input.item.json;
const order = data.order || data;
const orderNumber = String(order.order_number || order.name || '').replace(/^#/, '');

// Generate 16-character alphanumeric random string
const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
let randomString = '';
for (let i = 0; i < 16; i++) {
  randomString += chars.charAt(Math.floor(Math.random() * chars.length));
}

// Filename without order number for security
const filename = `${randomString}.pdf`;

return {
  json: {
    ...data,
    _gdrive: {
      filename: filename,
      randomId: randomString,
      orderNumber: orderNumber
    }
  },
  binary: $input.item.binary
};

// Build share link and collect all data for metafield update
const shareData = $input.item.json;
const fileId = shareData.id;

// Get data from Generate Random Filename node
const gdriveData = $('Generate Random Filename').first().json._gdrive;

// Get all previous data
const prevData = $('Generate Random Filename').first().json;

// Build share URL
const shareUrl = `https://drive.google.com/file/d/${fileId}/view?usp=sharing`;

return {
  json: {
    ...prevData,
    _gdrive: {
      ...gdriveData,
      fileId: fileId,
      shareUrl: shareUrl
    }
  },
  binary: $('Generate Random Filename').first().binary
};

// Prepare email data for invoice sending
// TUF-120: Optimized email with locale support, Du-form, conditional due date
// TUF-121: Locale-based language selection (DE vs EN)
// TUF-122: German text in "Du" form
// TUF-123: Due date hint only for invoice orders

const data = $input.item.json;
const order = data.order || data._order || data;
const gdrive = data._gdrive;

// Recipient info
const recipientEmail = order.customer?.email || order.email || '';
const recipientFirstName = order.customer?.first_name || order.billing_address?.first_name || '';

// Order details
const orderNumber = String(order.order_number || order.name || '').replace(/^#/, '');
const orderName = order.name || `#${orderNumber}`;
const totalPrice = parseFloat(order.total_price || 0).toFixed(2);
const currency = order.currency || 'CHF';

// Due date calculation
const dueDate = data._dueDate || (() => {
  const orderDate = new Date(order.created_at);
  const due = new Date(orderDate);
  due.setDate(due.getDate() + 30);
  return due.toISOString().split('T')[0];
})();
const dueDateFormatted = new Date(dueDate).toLocaleDateString('de-CH');

// Order type checks
const isShopOrder = order.source_name !== 'pos';
const isPosOrder = order.source_name === 'pos';
const isInvoiceOrder = data._isInvoiceOrder === true;
const hasEmail = !!recipientEmail;

// TUF-121: Locale detection - default to German for German-speaking customers
const customerLocale = (order.customer?.locale || order.customer_locale || 'de').toLowerCase();
const isGerman = customerLocale.startsWith('de');

// TUF-123: Show due date only for invoice orders
const showDueDate = isInvoiceOrder;

// TUF-122: German text in "Du" form
const emailContent = isGerman ? {
  subject: `Deine Rechnung ${orderName} von Tuftinglove`,
  greeting: recipientFirstName ? `Hallo ${recipientFirstName}` : 'Hallo',
  thankYou: 'Vielen Dank für deine Bestellung bei Tuftinglove!',
  invoiceText: `Anbei findest du deine Rechnung ${orderName}.`,
  amountLabel: 'Rechnungsbetrag',
  dueDateLabel: 'Zahlbar bis',
  paymentNote: 'Bitte überweise den Betrag mit dem beigefügten QR-Einzahlungsschein.',
  viewOnline: 'Rechnung online ansehen',
  contactNote: 'Bei Fragen erreichst du uns unter',
  signature: 'Liebe Grüsse',
  team: 'Jenni und das Tuftinglove-Team'
} : {
  subject: `Your invoice ${orderName} from Tuftinglove`,
  greeting: recipientFirstName ? `Hello ${recipientFirstName}` : 'Hello',
  thankYou: 'Thank you for your order at Tuftinglove!',
  invoiceText: `Please find your invoice ${orderName} attached.`,
  amountLabel: 'Invoice amount',
  dueDateLabel: 'Due by',
  paymentNote: 'Please transfer the amount using the attached QR payment slip.',
  viewOnline: 'View invoice online',
  contactNote: 'For questions, reach us at',
  signature: 'Best regards',
  team: 'Jenni and the Tuftinglove Team'
};

// Send logic
const shouldSendEmail = hasEmail && (isShopOrder || isInvoiceOrder);
const shouldSendSlack = isPosOrder && isInvoiceOrder && !hasEmail;

return {
  json: {
    ...data,
    _email: {
      to: recipientEmail,
      subject: emailContent.subject,
      recipientFirstName: recipientFirstName,
      orderNumber: orderNumber,
      orderName: orderName,
      totalPrice: totalPrice,
      currency: currency,
      dueDate: dueDateFormatted,
      gdriveLink: gdrive?.share_url || gdrive?.shareUrl || '',
      // Localized content
      isGerman: isGerman,
      showDueDate: showDueDate,
      content: emailContent
    },
    _isShopOrder: isShopOrder,
    _isPosOrder: isPosOrder,
    _isInvoiceOrder: isInvoiceOrder,
    _hasEmail: hasEmail,
    _shouldSendEmail: shouldSendEmail,
    _shouldSendSlack: shouldSendSlack
  },
  binary: $input.item.binary
};

const data = $input.item.json;
const order = data._order || data;
const gdrive = data._gdrive;
const orderNumber = String(order.order_number || order.name).replace('#', '');
const totalPrice = parseFloat(order.total_price || 0).toFixed(2);
const currency = order.currency || 'CHF';
const customerName = order.customer?.first_name && order.customer?.last_name
  ? `${order.customer.first_name} ${order.customer.last_name}`
  : order.billing_address?.name || 'Unbekannt';
const hasEmail = !!(order.customer?.email || order.email);
const customerEmail = order.customer?.email || order.email || 'Keine E-Mail';
const orderDate = new Date(order.created_at);
const dueDate = new Date(orderDate);
dueDate.setDate(dueDate.getDate() + 30);
const dueDateFormatted = dueDate.toLocaleDateString('de-CH');
const blocks = [
  {"type": "header", "text": {"type": "plain_text", "text": "POS Rechnung erstellt", "emoji": true}},
  {"type": "section", "fields": [
    {"type": "mrkdwn", "text": `*Bestellung:*\n#${orderNumber}`},
    {"type": "mrkdwn", "text": `*Betrag:*\n${currency} ${totalPrice}`},
    {"type": "mrkdwn", "text": `*Kunde:*\n${customerName}`},
    {"type": "mrkdwn", "text": `*Faellig bis:*\n${dueDateFormatted}`}
  ]},
  {"type": "section", "text": {"type": "mrkdwn", "text": `*E-Mail:* ${hasEmail ? customerEmail : 'Keine E-Mail hinterlegt'}`}},
  {"type": "actions", "elements": [
    {"type": "button", "text": {"type": "plain_text", "text": "Rechnung ansehen", "emoji": true}, "url": gdrive?.share_url || '', "action_id": "view_invoice"}
  ]}
];
return {
  json: {...data, _slack: {channel: '#tuftinglove-invoices', blocksJson: JSON.stringify(blocks)}},
  binary: $input.item.binary
};
